MAX_UPLOAD_SIZE = 500 * 1024 * 1024  # 500MB max upload
UPLOAD_CHUNK_SIZE = 1024 * 1024       # 1MB chunks for streaming write

@app.post("/upload")
async def upload_file(file: UploadFile = File(...)):
    try:
        ext = Path(file.filename).suffix or ".tmp"
        filename = f"{uuid.uuid4()}{ext}"
        save_path = UPLOADS_DIR / filename

        # Stream file to disk in chunks to avoid loading entire file into memory
        total_written = 0
        with open(save_path, "wb") as f:
            while True:
                chunk = await file.read(UPLOAD_CHUNK_SIZE)
                if not chunk:
                    break
                total_written += len(chunk)
                if total_written > MAX_UPLOAD_SIZE:
                    # Clean up partial file
                    f.close()
                    save_path.unlink(missing_ok=True)
                    raise HTTPException(
                        status_code=413,
                        detail=f"File too large. Maximum upload size is {MAX_UPLOAD_SIZE // (1024*1024)}MB"
                    )
                f.write(chunk)

        size_mb = total_written / (1024 * 1024)
        print(f"File '{file.filename}' uploaded ({size_mb:.1f}MB) to '{save_path}'")
        url = f"/ui/uploads/{filename}"
        return {"url": url}
    except HTTPException:
        raise
    except Exception as e:
        print(f"ERROR: File upload failed: {e}")
        raise HTTPException(status_code=500, detail=f"File upload failed: {e}")


# -----------------------------------------------------------------------------
# Session-based upload for Agent Mode
# Files are stored in session-specific folders that Claude Code can access
# -----------------------------------------------------------------------------
SESSION_UPLOADS_DIR = UPLOADS_DIR / "sessions"

@app.post("/upload/session")
async def upload_session_file(
    file: UploadFile = File(...),
    session_id: str = Form(...)
):
    """Upload file to session-specific folder for Claude Code agent.

    Files are stored at: Portal/uploads/sessions/{session_id}/{original_filename}
    This allows Claude Code to access files directly using its file reading tools.
    """
    try:
        # Create session folder if it doesn't exist
        session_folder = SESSION_UPLOADS_DIR / session_id
        session_folder.mkdir(parents=True, exist_ok=True)

        # Use original filename (or add UUID prefix if collision)
        original_name = Path(file.filename).name
        save_path = session_folder / original_name

        # Handle filename collisions by adding timestamp prefix
        if save_path.exists():
            import time
            timestamp = int(time.time())
            stem = Path(original_name).stem
            ext = Path(original_name).suffix
            save_path = session_folder / f"{stem}_{timestamp}{ext}"

        # Stream file to disk in chunks to avoid loading entire file into memory
        total_written = 0
        with open(save_path, "wb") as f:
            while True:
                chunk = await file.read(UPLOAD_CHUNK_SIZE)
                if not chunk:
                    break
                total_written += len(chunk)
                if total_written > MAX_UPLOAD_SIZE:
                    f.close()
                    save_path.unlink(missing_ok=True)
                    raise HTTPException(
                        status_code=413,
                        detail=f"File too large. Maximum upload size is {MAX_UPLOAD_SIZE // (1024*1024)}MB"
                    )
                f.write(chunk)

        # Get absolute path for Claude Code
        abs_path = str(save_path.resolve())
        # Also provide relative URL for web access
        relative_url = f"/ui/uploads/sessions/{session_id}/{save_path.name}"

        size_mb = total_written / (1024 * 1024)
        print(f"[Session Upload] File '{file.filename}' ({size_mb:.1f}MB) saved to '{abs_path}'")

        return {
            "url": relative_url,
            "path": abs_path,
            "filename": save_path.name,
            "session_id": session_id,
            "session_folder": str(session_folder.resolve())
        }
    except HTTPException:
        raise
    except Exception as e:
        print(f"ERROR: Session file upload failed: {e}")
        raise HTTPException(status_code=500, detail=f"Session file upload failed: {e}")


@app.get("/upload/session/{session_id}")
async def list_session_files(session_id: str):
    """List all files in a session's upload folder."""
    try:
        session_folder = SESSION_UPLOADS_DIR / session_id
        if not session_folder.exists():
            return {"files": [], "session_folder": None}

        files = []
        for f in session_folder.iterdir():
            if f.is_file():
                files.append({
                    "filename": f.name,
                    "path": str(f.resolve()),
                    "url": f"/ui/uploads/sessions/{session_id}/{f.name}",
                    "size": f.stat().st_size,
                    "modified": f.stat().st_mtime
                })

        return {
            "files": files,
            "session_folder": str(session_folder.resolve()),
            "count": len(files)
        }
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))


@app.delete("/upload/session/{session_id}")
async def cleanup_session_files(session_id: str):
    """Delete all files in a session's upload folder."""
    try:
        import shutil
        session_folder = SESSION_UPLOADS_DIR / session_id
        if session_folder.exists():
            shutil.rmtree(session_folder)
            print(f"[Session Cleanup] Deleted session folder: {session_folder}")
            return {"deleted": True, "session_id": session_id}
        return {"deleted": False, "message": "Session folder not found"}
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))


def cleanup_old_session_files(max_age_days: int = 3):
    """Clean up session folders older than max_age_days.

    Called periodically to prevent unbounded file growth.
    """
    import time
    import shutil

    if not SESSION_UPLOADS_DIR.exists():
        return 0

    cutoff_time = time.time() - (max_age_days * 24 * 60 * 60)
    cleaned = 0

    for session_folder in SESSION_UPLOADS_DIR.iterdir():
        if session_folder.is_dir():
            # Check folder modification time
            try:
                mtime = session_folder.stat().st_mtime
                if mtime < cutoff_time:
                    shutil.rmtree(session_folder)
                    print(f"[Session Cleanup] Removed old session folder: {session_folder.name}")
                    cleaned += 1
            except Exception as e:
                print(f"[Session Cleanup] Error cleaning {session_folder}: {e}")

    return cleaned


@app.post("/upload/cleanup")
async def trigger_session_cleanup(max_age_days: int = 3):
    """Manually trigger cleanup of old session files."""
    cleaned = cleanup_old_session_files(max_age_days)
    return {"cleaned_sessions": cleaned, "max_age_days": max_age_days}

@app.get("/health")
def health():
    try:
        gm_digest, gm_bytes = verify_gm_or_halt()
        status = "ok"
        detail = ""
    except HTTPException as e:
        gm_digest, gm_bytes = "", 0
        status = "GM FAIL"
        detail = str(e)
    vol_bytes = VOL_PATH.stat().st_size if VOL_PATH.exists() else 0
    # Count snapshots from index
    try:
        snapshot_count = len(json.loads(SNAPSHOT_INDEX.read_text())) if SNAPSHOT_INDEX.exists() else 0
    except Exception:
        snapshot_count = 0
    try:
        pairing = {
            "default_origin": CFG.get("pairing", "default_origin", fallback=""),
            "default_operator": CFG.get("pairing", "default_operator", fallback=""),
        }
    except Exception:
        pairing = {"default_origin": "", "default_operator": ""}
    # Build per-operator turn data for checkpoint tracking
    operator_turns = {}
    for op, s in state_by_op.items():
        # Calculate turns until next checkpoint using countdown-based logic
        # This matches the logic in should_create_checkpoint()
        turns_since_last_checkpoint = s.total_turns - s.last_checkpoint_turn

        # Calculate how many turns until the next checkpoint
        # The checkpoint triggers when turns_since >= interval, so we need (interval - turns_since)
        turns_until_checkpoint = CHECKPOINT_AUTO_CREATE_INTERVAL - turns_since_last_checkpoint

        # If we're at or past the checkpoint threshold, show 0 (checkpoint needed now)
        if turns_until_checkpoint <= 0:
            turns_until_checkpoint = 0

        operator_turns[op] = {
            "total_turns": s.total_turns,
            "turns_until_checkpoint": turns_until_checkpoint,
            "total_tokens": s.total_tokens
        }

    return {
        "status": status, "detail": detail, "gm_sha256": gm_digest,"worker_running": models_module.worker_running,"queue_size": len(task_queue),
        "gm_bytes": gm_bytes, "volume_bytes": vol_bytes, "snapshot_count": snapshot_count, "drift": drift_state_global(),
        "ctx_used": max((s.context_used for s in state_by_op.values()), default=0),
        "ctx_max": CTX_MAX, "latest_manifest": json.loads(MANIFEST.read_text()),
        "audio_engine": AUDIO_ENGINE, "tts_model": TTS_MODEL, "stt_model": STT_MODEL,
        "users": {"list": USERS_LIST, "default": USERS_DEFAULT}, "pairing": pairing,
        "operator_turns": operator_turns,  # Per-operator turn counts, checkpoint countdown, and cumulative tokens
        "checkpoint_config": {
            "turns_to_compress": CHECKPOINT_TURNS_TO_COMPRESS,
            "auto_create_interval": CHECKPOINT_AUTO_CREATE_INTERVAL,
            "min_snapshots_required": CHECKPOINT_MIN_SNAPSHOTS
        }
    }

