@app.get("/dashboard")
def dashboard():
    """User-friendly system dashboard for monitoring appliance health."""
    usage = get_disk_usage()

    # Check API keys configuration
    api_keys_configured = {
        "openai": bool(OPENAI_API_KEY.strip()),
        "anthropic": bool(ANTHROPIC_API_KEY.strip()),
        "google": bool(GOOGLE_API_KEY.strip())
    }

    # Get last activity timestamps
    last_activities = {}
    for op, s in state_by_op.items():
        if s.last_mint_ms and s.last_mint_ms > 0:
            # Convert milliseconds to ISO timestamp
            from datetime import datetime
            last_activities[op] = datetime.fromtimestamp(s.last_mint_ms / 1000).isoformat()

    # Overall system health
    health_status = "healthy"
    health_issues = []

    if usage["disk"]["percent"] > 90:
        health_status = "critical"
        health_issues.append("Disk space critical")
    elif usage["disk"]["percent"] > 80:
        health_status = "warning"
        health_issues.append("Disk space low")

    if not any(api_keys_configured.values()):
        health_status = "warning"
        health_issues.append("No API keys configured")

    if usage["archives"]["count"] > 300:
        if health_status == "healthy":
            health_status = "info"
        health_issues.append(f"Archive cleanup recommended ({usage['archives']['count']} files)")

    # Get task statistics
    try:
        import sqlite3
        from datetime import datetime, timezone, timedelta
        db_path = Path("Portal/tasks.db")
        task_stats = {
            "active": 0,
            "completed_last_24h": 0,
            "failed": 0,
            "total": 0
        }

        if db_path.exists():
            conn = sqlite3.connect(str(db_path))
            cursor = conn.cursor()

            # Count active tasks
            cursor.execute("SELECT COUNT(*) FROM tasks WHERE status IN ('processing', 'pending')")
            task_stats["active"] = cursor.fetchone()[0]

            # Count completed in last 24h
            cutoff = (datetime.now(timezone.utc) - timedelta(hours=24)).isoformat().replace('+00:00', 'Z')
            cursor.execute("SELECT COUNT(*) FROM tasks WHERE status='completed' AND updated_at > ?", (cutoff,))
            task_stats["completed_last_24h"] = cursor.fetchone()[0]

            # Count failed tasks
            cursor.execute("SELECT COUNT(*) FROM tasks WHERE status='failed'")
            task_stats["failed"] = cursor.fetchone()[0]

            # Total tasks
            cursor.execute("SELECT COUNT(*) FROM tasks")
            task_stats["total"] = cursor.fetchone()[0]

            conn.close()
    except Exception as e:
        task_stats = {"error": str(e)}

    return {
        "health_status": health_status,
        "health_issues": health_issues,
        "disk_usage": usage,
        "api_keys_configured": api_keys_configured,
        "last_activities": last_activities,
        "archive_status": {
            "count": usage["archives"]["count"],
            "size_mb": usage["archives"]["size_mb"],
            "auto_cleanup_enabled": True,
            "cleanup_settings": {
                "days_to_keep": 30,
                "max_size_gb": 5.0,
                "max_files": 200
            }
        },
        "system_uptime": get_system_uptime(),
        "service_status": "running",  # If we're responding, we're running
        "worker_status": "running" if models_module.worker_running else "stopped",
        "queue_size": len(task_queue),
        "task_status": task_stats,
        "task_cleanup": {
            "auto_cleanup_enabled": True,
            "max_stuck_hours": 24,
            "cleanup_runs_with": "watchdog (every 2 minutes)"
        }
    }

@app.post("/cleanup/archives")
def cleanup_archives_manual(
    days_to_keep: int = 30,
    max_size_gb: float = 5.0,
    max_files: int = 200,
    dry_run: bool = False
):
    """Manually trigger archive cleanup with custom parameters."""
    if dry_run:
        # Just check what would be deleted
        stats = cleanup_old_archives(days_to_keep, max_size_gb, max_files)
        # Restore files since this was a dry run (hacky but works)
        return {"dry_run": True, "would_delete": stats}

    stats = cleanup_old_archives(days_to_keep, max_size_gb, max_files)
    return {
        "dry_run": False,
        "cleanup_stats": stats,
        "disk_usage_after": get_disk_usage()
    }

@app.get("/watchdog")
def watchdog():
    """Systemd watchdog endpoint - returns 200 if service is healthy."""
    # Check critical components
    checks = {
        "volume_accessible": VOL_PATH.exists(),
        "manifest_accessible": MANIFEST.exists(),
        "worker_running": models_module.worker_running,
        "database_accessible": Path("Portal/tasks.db").exists()
    }

    # Check disk space
    usage = get_disk_usage()
    checks["disk_space_ok"] = usage["disk"]["percent"] < 95

    # Clean up stuck tasks periodically (runs every watchdog check)
    try:
        task_cleanup = cleanup_stuck_tasks(max_hours=24)
        checks["stuck_tasks_cleaned"] = task_cleanup["marked_failed"]
    except Exception as e:
        checks["stuck_tasks_error"] = str(e)

    # If any critical check fails, return error
    if not all([checks["volume_accessible"], checks["manifest_accessible"],
                checks["disk_space_ok"]]):
        raise HTTPException(status_code=503, detail=f"Service unhealthy: {checks}")

    return {"status": "healthy", "checks": checks}

def get_system_uptime() -> str:
    """Get system uptime in human-readable format."""
    try:
        with open('/proc/uptime', 'r') as f:
            uptime_seconds = float(f.readline().split()[0])

        days = int(uptime_seconds // 86400)
        hours = int((uptime_seconds % 86400) // 3600)
        minutes = int((uptime_seconds % 3600) // 60)

        if days > 0:
            return f"{days}d {hours}h {minutes}m"
        elif hours > 0:
            return f"{hours}h {minutes}m"
        else:
            return f"{minutes}m"
    except Exception:
        return "unknown"

