def _fetch_google_models() -> dict | None:
    """Live-fetch chat-capable Gemini models via the google-generativeai SDK."""
    import google.generativeai as genai
    genai.configure(api_key=GOOGLE_API_KEY)
    models = []
    skip_keywords = ("embedding", "aqa", "bisheng", "learnlm")
    for m in genai.list_models():
        model_id = m.name.replace("models/", "")
        if "generateContent" not in m.supported_generation_methods:
            continue
        if not model_id.startswith("gemini"):
            continue
        if any(kw in model_id.lower() for kw in skip_keywords):
            continue
        display_name = model_id.replace("gemini-", "Gemini ").replace("-", " ").title()
        models.append({"id": model_id, "name": display_name})
    return _wrap("google", models, "live") if models else None


def _fetch_anthropic_models() -> dict | None:
    """Live-fetch Claude models via the official Anthropic SDK (added 2024+)."""
    import anthropic
    client = anthropic.Anthropic(api_key=ANTHROPIC_API_KEY, timeout=5.0)
    models = []
    # Paginate (default limit=20, max 1000). The Claude catalog is small;
    # one page is plenty.
    page = client.models.list(limit=100)
    for m in page.data:
        model_id = getattr(m, "id", None)
        if not model_id or not model_id.startswith("claude-"):
            continue
        display = getattr(m, "display_name", None) or model_id
        models.append({"id": model_id, "name": display})
    return _wrap("anthropic", models, "live") if models else None


def _fetch_openai_models() -> dict | None:
    """Live-fetch GPT models via the OpenAI SDK."""
    import openai
    client = openai.OpenAI(api_key=OPENAI_API_KEY, timeout=5.0)
    models = []
    for m in client.models.list().data:
        if not m.id.startswith("gpt-") and not m.id.startswith("o"):
            continue
        # 'o3', 'o4-mini' etc. are reasoning models — include them too
        display_name = m.id.upper().replace("-", " ")
        models.append({"id": m.id, "name": display_name})
    return _wrap("openai", models, "live") if models else None


def _fetch_xai_models() -> dict | None:
    """Live-fetch Grok models via xAI's OpenAI-compatible /v1/models endpoint.

    xAI exposes an OpenAI-compatible API surface (per their docs). The
    openai SDK works against it with base_url override. Filter to chat
    Grok models only — exclude grok-imagine-* (image/video gen) per
    audit M9.
    """
    if not XAI_API_KEY:
        return None  # No API key → fall through to fallback
    import openai
    client = openai.OpenAI(
        api_key=XAI_API_KEY,
        base_url="https://api.x.ai/v1",
        timeout=5.0,
    )
    models = []
    for m in client.models.list().data:
        if not m.id.startswith("grok-"):
            continue
        if m.id.startswith("grok-imagine-"):
            continue  # image/video generation — not for chat dropdown
        # xAI's IDs are already brand-formatted (grok-4.3) so just clean for display
        display_name = m.id.replace("grok-", "Grok ").replace("-", " ").title()
        models.append({"id": m.id, "name": display_name})
    return _wrap("xai", models, "live") if models else None


_FETCHERS = {
    "google": _fetch_google_models,
    "anthropic": _fetch_anthropic_models,
    "openai": _fetch_openai_models,
    "xai": _fetch_xai_models,
}


def _wrap(provider: str, models: list, source: str) -> dict:
    """Build the canonical response envelope. Locked contract — both
    frontends parse this shape (see plan T1 verification)."""
    import datetime as _dt
    return {
        "provider": provider,
        "models": models,
        "source": source,
        "default_id": _DEFAULT_MODEL.get(provider, ""),
        "fetched_iso": _dt.datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ"),
    }


@app.get("/models/{provider}")
def get_available_models(provider: str):
    """Return the list of chat-capable models for the given provider.

    Tries the live upstream API first (cached 10 minutes on success).
    On failure (missing key, network error, upstream 500) falls back to
    a hardcoded static list (cached 30 seconds — short, so we recover
    quickly when upstream comes back). See Orchestrator/utils/models_cache.py
    for the cache semantics.

    Response shape (audit I12 locked contract):
        {
            "provider": "xai",
            "models": [{"id": "grok-4.3", "name": "Grok 4.3"}, ...],
            "source": "live" | "fallback",
            "default_id": "grok-4.3",
            "fetched_iso": "2026-05-18T20:30:00Z",
            "cached": true | false
        }

    Frontends use `default_id` to pre-select the dropdown option; the
    `(Auto - Latest)` placeholder is preserved by the frontend code, not
    inserted server-side.
    """
    provider = provider.lower()
    if provider not in _FALLBACK_MODELS:
        raise HTTPException(404, f"Unknown provider: {provider}")

    fetcher = _FETCHERS.get(provider)
    return _models_cache_get(
        provider,
        fetcher=(lambda f=fetcher: f()) if fetcher else (lambda: None),
        fallback=lambda p=provider: _wrap(p, _FALLBACK_MODELS[p], "fallback"),
    )

@app.get("/tail")
def tail():
    return parse_tail(read_text_safe(VOL_PATH))

@app.get("/recall")
def recall():
    vol = read_text_safe(VOL_PATH)
    ends = list(END_RX.finditer(vol))
    if not ends: return {"prior": ""}
    end_m = ends[-1]
    snap_id = end_m.group("snap")
    starts_before = list(START_RX.finditer(vol, 0, end_m.start()))
    start_m = next((m for m in reversed(starts_before) if m.group("snap") == snap_id), None)
    if not start_m: raise HTTPException(500, "PARTIAL-SNAPSHOT")
    return {"prior": vol[start_m.start(): end_m.end()]}

@app.get("/assert")
def assert_volume():
    if not VOL_PATH.exists(): return {"bytes": 0, "sha256": "", "volume": ""}
    b = VOL_PATH.read_bytes()
    vol_text = b.decode('utf-8', errors='replace')
    return {"bytes": len(b), "sha256": sha256_bytes(b), "volume": vol_text}

