@app.get("/artifact")
def artifact(which: str = "latest", utc: Optional[str] = None):
    if which == "latest":
        man = json.loads(MANIFEST.read_text())
        if not man["archive"]: raise HTTPException(404, "No archive yet")
        return FileResponse(Path(man["archive"][-1]["path"]))
    elif utc:
        p = ARC_DIR / f"Volume_{utc}.txt"
        if not p.exists(): raise HTTPException(404, "Not found")
        return FileResponse(p)
    raise HTTPException(400, "Specify which=latest or utc=...")

@app.get("/artifacts/{artifact_id}")
def download_artifact(artifact_id: str):
    """Serve generated artifact file for download."""
    # Sanitize path to prevent directory traversal
    safe_id = Path(artifact_id).name
    artifact_path = ARTIFACTS_DIR / safe_id

    if not artifact_path.exists():
        raise HTTPException(404, "Artifact not found or expired")

    # Determine content type based on file extension
    suffix = artifact_path.suffix.lower()
    content_types = {
        '.txt': 'text/plain',
        '.md': 'text/markdown',
        '.json': 'application/json',
        '.py': 'text/x-python',
        '.js': 'text/javascript',
        '.pdf': 'application/pdf',
        '.csv': 'text/csv',
        '.docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    }
    media_type = content_types.get(suffix, 'application/octet-stream')

    # Extract original filename from artifact_id (format: operator_uuid_filename)
    parts = safe_id.split('_', 2)
    original_filename = parts[2] if len(parts) >= 3 else safe_id

    return FileResponse(artifact_path, media_type=media_type, filename=original_filename)

@app.post("/artifacts/reprocess")
def reprocess_artifacts(body: dict = Body(...)):
    """Re-process raw artifact tags in content and return HTML with download buttons.

    This is used to fix bubbles that show raw [ARTIFACT:...] tags instead of download buttons,
    typically for content generated before the frontend fix was applied.
    """
    from Orchestrator.artifacts import parse_and_process_artifacts

    content = body.get("content", "")
    operator = body.get("operator", "unknown")

    if not content or '[ARTIFACT:' not in content:
        return {"processed_html": None, "message": "No artifact tags found"}

    # Process the content through the artifact generator
    processed = parse_and_process_artifacts(content, operator)

    return {"processed_html": processed}

@app.post("/mint")
def mint_manual(body: dict = Body(None)):
    """Create a snapshot, optionally with provided content.

    If 'content' is provided, creates a snapshot with that content directly.
    Otherwise, creates a snapshot from the conversation log.
    """
    from Orchestrator.checkpoint import mint_with_content

    body = body or {}
    operator = body.get("operator")
    op = (operator or CURRENT_OPERATOR or USERS_DEFAULT).strip()
    content = body.get("content")
    snap_type = body.get("type", "normal")

    try:
        if content:
            # Content provided - use direct minting
            print(f"[MINT] Direct content mint for operator {op}, content length: {len(content)}")
            return mint_with_content(op, content, reason="MCP", snap_type=snap_type)
        else:
            # No content - use conversation log
            return perform_mint(op, "MANUAL")
    except Exception as e:
        import traceback
        print(f"[ERROR] /mint failed:\n{traceback.format_exc()}")
        return {"status": "error", "error": str(e)}


@app.post("/agent/dev-snapshot")
def create_dev_snapshot(body: dict = Body(...)):
    """Create a development snapshot with provided content.

    This endpoint is used by CLI agents (Gemini CLI, Claude Code) to create
    snapshots with detailed session logs.

    Required body fields:
        - content: The snapshot content (detailed session log)
        - operator: The operator name (e.g., "Brandon-DEV")
    """
    from Orchestrator.checkpoint import mint_with_content

    content = body.get("content", "")
    operator = body.get("operator", "Brandon-DEV")

    if not content:
        return {"success": False, "error": "Content is required"}

    if len(content) < 50:
        return {"success": False, "error": "Content too short - provide detailed session log"}

    try:
        result = mint_with_content(operator, content, reason="DEV-SNAPSHOT", snap_type="normal")
        return {
            "success": True,
            "snap_id": result.get("snap_id"),
            "message": f"Development snapshot created: {result.get('snap_id')}",
            "operator": operator
        }
    except Exception as e:
        import traceback
        print(f"[ERROR] /agent/dev-snapshot failed:\n{traceback.format_exc()}")
        return {"success": False, "error": str(e)}

@app.post("/checkpoint")
async def create_checkpoint_manual(body: dict = Body(None)):
    """Create a manual checkpoint for the specified operator"""
    operator = (body or {}).get("operator") # Read operator from JSON body
    op = (operator or CURRENT_OPERATOR or USERS_DEFAULT).strip()
    try:
        s = get_state(op)
        # Trigger checkpoint creation in background thread (fire-and-forget)
        import threading
        threading.Thread(target=create_checkpoint_async, args=(op, True), daemon=True).start()

        return {
            "status": "success",
            "message": f"Checkpoint creation initiated for {op}",
            "operator": op,
            "turn": s.total_turns
        }
    except Exception as e:
        import traceback
        print(f"[ERROR] /checkpoint failed:\n{traceback.format_exc()}")
        return {"status": "error", "error": str(e)}

@app.post("/operator/add")
def add_operator(body: dict = Body(...)):
    """Add a new operator to config.ini and reload the operator list"""
    operator_name = (body or {}).get("name", "").strip()

    if not operator_name:
        raise HTTPException(status_code=400, detail="Operator name is required")

    try:
        global USERS_LIST, CFG

        # Read current operators from config
        current_list = USERS_LIST.copy()

        # Check if operator already exists
        if operator_name in current_list:
            return {
                "status": "exists",
                "message": f"Operator '{operator_name}' already exists",
                "operators": current_list
            }

        # Add new operator
        current_list.append(operator_name)

        # Update config.ini file
        config_path = Path("config.ini")
        CFG.set("users", "list", ", ".join(current_list))

        with open(config_path, "w") as f:
            CFG.write(f)

        # Reload the config to update the global variable
        CFG.read(config_path)
        USERS_LIST = [u.strip() for u in CFG.get("users","list",fallback="Brandon").split(",") if u.strip()]

        return {
            "status": "success",
            "message": f"Operator '{operator_name}' added successfully",
            "operators": USERS_LIST
        }
    except Exception as e:
        import traceback
        print(f"[ERROR] /operator/add failed:\n{traceback.format_exc()}")
        return {"status": "error", "error": str(e)}


@app.delete("/operator/{name}")
def remove_operator(name: str):
    """Remove an operator from config.ini and reload USERS_LIST.

    Idempotent: returns 200 with status='removed' if found, status='not_present' if absent.
    Refuses 400 if attempting to remove the LAST operator (must always have at least one).
    """
    if not name or not name.strip():
        raise HTTPException(status_code=400, detail="Operator name required")
    name = name.strip()

    global USERS_LIST, CFG
    current_list = USERS_LIST.copy()

    if name not in current_list:
        return {
            "status": "not_present",
            "message": f"Operator '{name}' not in list",
            "operators": current_list,
        }

    if len(current_list) == 1:
        raise HTTPException(
            status_code=400,
            detail="Cannot remove the last operator — at least one must remain",
        )

    current_list.remove(name)

    config_path = Path("config.ini")
    CFG.set("users", "list", ", ".join(current_list))
    with open(config_path, "w") as f:
        CFG.write(f)
    CFG.read(config_path)
    USERS_LIST = [u.strip() for u in CFG.get("users", "list", fallback="Brandon").split(",") if u.strip()]

    return {
        "status": "removed",
        "message": f"Operator '{name}' removed",
        "operators": USERS_LIST,
    }


